import{c as t,S as h,j as i,m as c}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Trích đoạn đề thi","description":"","frontmatter":{},"headers":[],"relativePath":"admin/trich-doan-de-thi.md","filePath":"admin/trich-doan-de-thi.md","lastUpdated":0}'),o={name:"admin/trich-doan-de-thi.md"};function a(r,n,l,g,s,u){return h(),i("div",null,[...n[0]||(n[0]=[c('<h1 id="trich-đoan-đe-thi" tabindex="-1">Trích đoạn đề thi <a class="header-anchor" href="#trich-đoan-đe-thi" aria-label="Permalink to “Trích đoạn đề thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/excerpt</code></p><p>Trích đoạn đề thi là <strong>một cụm câu hỏi dùng chung ngữ cảnh</strong> (đoạn văn, bảng số liệu, hình ảnh, đồ thị…). Khi học viên làm bài, các câu trong cùng trích đoạn được hiển thị bên cạnh ngữ cảnh chung đó.</p><h2 id="khi-nao-dung" tabindex="-1">Khi nào dùng <a class="header-anchor" href="#khi-nao-dung" aria-label="Permalink to “Khi nào dùng”">​</a></h2><ul><li><strong>Đọc hiểu</strong> (Tiếng Việt, tiếng Anh): một đoạn văn → 4-6 câu hỏi xoay quanh.</li><li><strong>HSA - Tư duy định tính</strong> (Văn, đọc hiểu): bài đọc kèm 5-7 câu hỏi.</li><li><strong>TSA - Đọc hiểu khoa học</strong>: đoạn về một thí nghiệm/hiện tượng + nhiều câu liên quan.</li><li><strong>TNTHPT - Tiếng Anh đọc hiểu</strong>, <strong>Lịch sử/Địa lý</strong> dạng dữ kiện.</li><li><strong>Khoa học</strong> (Lý/Hóa/Sinh): bài thí nghiệm có nhiều câu phân tích.</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Nếu chỉ có 1 câu duy nhất gắn với ngữ cảnh, không cần dùng trích đoạn — bạn có thể chèn thẳng ngữ cảnh vào đề câu hỏi. Trích đoạn chỉ thực sự hữu ích khi <strong>≥ 2 câu</strong> chia sẻ chung một nội dung.</p></div><h2 id="danh-sach-trich-đoan" tabindex="-1">Danh sách trích đoạn <a class="header-anchor" href="#danh-sach-trich-đoan" aria-label="Permalink to “Danh sách trích đoạn”">​</a></h2><p>Cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tiêu đề</td><td>Tên gợi nhớ của trích đoạn</td></tr><tr><td>Môn</td><td>Môn áp dụng</td></tr><tr><td>Kỳ thi</td><td>ĐGNL (HSA) / ĐGTD (TSA) / TNTHPT / Khác</td></tr><tr><td>Số câu liên kết</td><td>Số câu hỏi đang dùng trích đoạn này</td></tr><tr><td>Người tạo</td><td>Tài khoản đã tạo</td></tr><tr><td>Ngày tạo</td><td></td></tr><tr><td>Trạng thái</td><td>Đang dùng / Ngưng</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Môn</strong>.</li><li>Theo <strong>Kỳ thi</strong>.</li><li>Theo <strong>Người tạo</strong>.</li><li>Tìm kiếm theo <strong>Tiêu đề</strong> hoặc <strong>nội dung trích đoạn</strong>.</li></ul><h2 id="tao-moi-trich-đoan" tabindex="-1">Tạo mới trích đoạn <a class="header-anchor" href="#tao-moi-trich-đoan" aria-label="Permalink to “Tạo mới trích đoạn”">​</a></h2><ol><li>Bấm <strong>Thêm mới</strong>.</li><li>Khai báo: <ul><li><strong>Tiêu đề</strong>: tên nội bộ (vd &quot;Đoạn văn về biến đổi khí hậu - HSA Văn&quot;).</li><li><strong>Môn</strong> áp dụng.</li><li><strong>Kỳ thi</strong> (ĐGNL / ĐGTD / TNTHPT / Khác).</li><li><strong>Chuyên đề / Chủ đề</strong> (tùy chọn).</li></ul></li><li>Soạn <strong>nội dung trích đoạn</strong> trong trình soạn thảo: <ul><li>Văn bản, định dạng, chèn ảnh.</li><li>Công thức toán (LaTeX) cho môn Toán/Lý/Hóa.</li><li>Bảng dữ liệu, biểu đồ (chèn ảnh).</li><li>File đính kèm (PDF, audio đối với tiếng Anh Listening).</li></ul></li><li>(Tùy chọn) Thêm <strong>nguồn / tác giả</strong> trích đoạn (vd &quot;Trích sách giáo khoa Ngữ văn 12 trang 45&quot;).</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Trích đoạn phải có <strong>nội dung rõ ràng, đầy đủ</strong>. Nếu nội dung bị lỗi format (font lạ, ảnh không hiển thị), tất cả câu hỏi liên kết đều bị ảnh hưởng.</p></div><h2 id="gan-cau-hoi-vao-trich-đoan" tabindex="-1">Gắn câu hỏi vào trích đoạn <a class="header-anchor" href="#gan-cau-hoi-vao-trich-đoan" aria-label="Permalink to “Gắn câu hỏi vào trích đoạn”">​</a></h2><p>Có 2 cách:</p><h3 id="cach-1-tu-trang-trich-đoan" tabindex="-1">Cách 1: Từ trang Trích đoạn <a class="header-anchor" href="#cach-1-tu-trang-trich-đoan" aria-label="Permalink to “Cách 1: Từ trang Trích đoạn”">​</a></h3><ol><li>Mở chi tiết trích đoạn.</li><li>Cuộn xuống mục <strong>Câu hỏi liên kết</strong>.</li><li>Bấm <strong>Thêm câu hỏi</strong> → mở popup chọn câu từ <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a>.</li><li>Chọn 1 hoặc nhiều câu → <strong>Lưu</strong>.</li></ol><h3 id="cach-2-khi-tao-sua-cau-hoi" tabindex="-1">Cách 2: Khi tạo / sửa câu hỏi <a class="header-anchor" href="#cach-2-khi-tao-sua-cau-hoi" aria-label="Permalink to “Cách 2: Khi tạo / sửa câu hỏi”">​</a></h3><ol><li>Vào <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a> → tạo / sửa câu.</li><li>Tại trường <strong>Trích đoạn</strong>, chọn trích đoạn đã tạo.</li><li>Lưu câu hỏi.</li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Cách 1 phù hợp khi bạn vừa tạo xong trích đoạn và muốn nhanh chóng thêm 5-6 câu cho nó. Cách 2 phù hợp khi nhập câu hỏi lẻ tẻ.</p></div><h2 id="sua-trich-đoan" tabindex="-1">Sửa trích đoạn <a class="header-anchor" href="#sua-trich-đoan" aria-label="Permalink to “Sửa trích đoạn”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Sửa</strong> trên dòng tương ứng.</li><li>Cập nhật tiêu đề, nội dung, môn…</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Sửa nội dung trích đoạn sẽ ảnh hưởng <strong>tất cả câu hỏi</strong> đang liên kết. Hãy kiểm tra lại các câu sau khi sửa để chắc chắn nội dung vẫn khớp.</p></div><h2 id="xoa-trich-đoan" tabindex="-1">Xóa trích đoạn <a class="header-anchor" href="#xoa-trich-đoan" aria-label="Permalink to “Xóa trích đoạn”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Xóa</strong>.</li><li>Xác nhận.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Nếu trích đoạn đang được câu hỏi nào đó tham chiếu, hệ thống <strong>không cho xóa</strong>. Bạn cần:</p><ul><li>Gỡ liên kết trên tất cả các câu hỏi liên quan, <strong>hoặc</strong></li><li>Xóa các câu hỏi liên quan trước, <strong>hoặc</strong></li><li>Đặt trích đoạn về trạng thái <strong>Ngưng</strong> (giữ lại để tham chiếu cũ vẫn hoạt động).</li></ul></div><h2 id="xem-truoc-hien-thi" tabindex="-1">Xem trước hiển thị <a class="header-anchor" href="#xem-truoc-hien-thi" aria-label="Permalink to “Xem trước hiển thị”">​</a></h2><p>Trên trang chi tiết trích đoạn, bấm <strong>Xem trước</strong>: hệ thống hiển thị giao diện học viên sẽ thấy — trích đoạn ở cột trái, các câu hỏi ở cột phải (hoặc trên dưới tùy thiết bị).</p><p>→ Dùng để kiểm tra format trước khi đề thi đi vào sử dụng.</p><h2 id="nhap-xuat" tabindex="-1">Nhập / Xuất <a class="header-anchor" href="#nhap-xuat" aria-label="Permalink to “Nhập / Xuất”">​</a></h2><ul><li><strong>Xuất Excel</strong> trích đoạn: tải về danh sách trích đoạn với nội dung text. Hữu ích để rà soát, sao lưu.</li><li>Nhập hàng loạt: hiện chưa hỗ trợ trực tiếp qua Excel do trích đoạn thường kèm ảnh/định dạng phức tạp. Khuyến nghị tạo thủ công từng cái hoặc nhập kèm khi nhập câu hỏi (xem <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a> - phần Nhập Excel).</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi có một bài Reading dài 500 chữ với 6 câu hỏi - nên tạo 1 trích đoạn hay 6 câu riêng?</strong> → Tạo <strong>1 trích đoạn</strong> chứa cả bài Reading, rồi liên kết 6 câu vào trích đoạn đó. Học viên sẽ thấy bài đọc ở bên cạnh khi làm 6 câu.</p><p><strong>Trích đoạn cũ có sửa được khi đã giao đề cho học viên?</strong> → Sửa được, nhưng <strong>không khuyến khích</strong> khi bài thi đang chấm. Hãy chờ kỳ thi kết thúc.</p><p><strong>Hai trích đoạn có nội dung giống hệt nhau, có nhập trùng không?</strong> → Hệ thống không tự kiểm tra trùng. Trước khi tạo mới, hãy tìm kiếm theo từ khóa nội dung để tránh trùng. Nếu trùng, gộp về 1 trích đoạn rồi xóa cái còn lại.</p><p><strong>Đối với bài Listening tiếng Anh (audio + nhiều câu), có dùng trích đoạn được không?</strong> → Có. Tải file audio lên trong nội dung trích đoạn, hệ thống hiển thị player audio cho học viên cùng với danh sách câu hỏi.</p><p><strong>Tại sao tôi không xóa được trích đoạn?</strong> → Vì còn câu hỏi đang gắn vào nó. Mở chi tiết → xem mục &quot;Câu hỏi liên kết&quot; → gỡ hoặc xóa các câu đó trước.</p>',38)])])}const m=t(o,[["render",a]]);export{d as __pageData,m as default};
